final:
module up_counter(
    input               clk     ,   
    input               arstn   ,

    output reg  [3:0]   count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge arstn or posedge dbg_halt)
begin
    if(!arstn)  count <= 4'b0000;
    else        count <= count + 1;
end

endmodule
